const body = $json.body || {};

const productUrl = body.product_url || "";
const questionSources = body.question_sources || ["product_page", "reviews", "competitors"];
const faqCount = Math.min(Math.max(parseInt(body.faq_count) || 20, 10), 30);
const tone = body.tone || "professional";
const language = body.language || "English";
const competitorComparison = body.competitor_comparison === true || body.competitor_comparison === "true";

if (!productUrl) {
  throw new Error("Missing required input: product_url");
}

return [{
  json: {
    product_url: productUrl,
    question_sources: questionSources,
    faq_count: faqCount,
    tone: tone,
    language: language,
    competitor_comparison: competitorComparison
  }
}];

const html = items[0].json.data || "";

const cleanText = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/\s+/g, ' ')
  .trim();

const inputs = items[0].json;

return [{
  json: {
    content: cleanText.slice(0, 10000),
    product_url: inputs.product_url,
    question_sources: inputs.question_sources,
    faq_count: inputs.faq_count,
    tone: inputs.tone,
    language: inputs.language,
    competitor_comparison: inputs.competitor_comparison
  }
}];

let raw = $json.output || "";

raw = raw.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();

const start = raw.indexOf('{');
const end = raw.lastIndexOf('}');

let classification = {};

try {
  classification = JSON.parse(raw.slice(start, end + 1));
} catch(e) {
  classification = {
    page_type: "product_page",
    industry: "general",
    business_model: "B2C",
    buying_journey_stage: "consideration",
    brand_name: "Unknown Brand",
    product_name: null,
    price_tier: "mid-range",
    target_customer: "general consumers",
    top_usps: [],
    key_themes: []
  };
}

const validateNode = $('Validate & Extract Inputs').first().json;
const cleanNode = $('Clean HTML').first().json;

return [{
  json: {
    product_url: validateNode.product_url,
    question_sources: validateNode.question_sources,
    faq_count: validateNode.faq_count,
    tone: validateNode.tone,
    language: validateNode.language,
    competitor_comparison: validateNode.competitor_comparison,
    content: cleanNode.content,
    classification: classification,
    is_product_page: ['product_page', 'landing_page'].includes(classification.page_type),
    is_brand_page: ['brand_homepage', 'about_page', 'category_page'].includes(classification.page_type),
    is_pricing_page: classification.page_type === 'pricing_page',
    is_decision_stage: classification.buying_journey_stage === 'decision',
    is_awareness_stage: classification.buying_journey_stage === 'awareness'
  }
}];

parameters.text:
=You are an expert customer researcher. Your job is to deeply understand what a customer needs to know before making a decision about this specific offering.

Here is what we know about this page:

URL: {{$json["product_url"]}}
Page Type: {{$json["classification"]["page_type"]}}
Industry: {{$json["classification"]["industry"]}}
Business Model: {{$json["classification"]["business_model"]}}
Buying Journey Stage: {{$json["classification"]["buying_journey_stage"]}}
Brand: {{$json["classification"]["brand_name"]}}
Product: {{$json["classification"]["product_name"]}}
Price Tier: {{$json["classification"]["price_tier"]}}
Target Customer: {{$json["classification"]["target_customer"]}}
Key USPs: {{$json["classification"]["top_usps"]}}
Key Themes: {{$json["classification"]["key_themes"]}}

PAGE CONTENT:
{{$json["content"]}}

Your task:

1. DEEP DIVE - Based on the page type and industry, extract:
   - If product page: exact specs, pricing details, compatibility, what problem it solves, what makes it different, known limitations
   - If brand/company page: full product/service range, pricing tiers, target segments, brand values, support model, geographic availability
   - If pricing page: plan differences, what's included/excluded, upgrade paths, billing terms, hidden costs

2. CUSTOMER HESITATIONS - List the top 8-10 specific hesitations a real customer at the {{$json["classification"]["buying_journey_stage"]}} stage would have. These must be specific to:
   - This exact industry ({{$json["classification"]["industry"]}})
   - This price tier ({{$json["classification"]["price_tier"]}})
   - This business model ({{$json["classification"]["business_model"]}})
   NOT generic hesitations like "is this worth it"

3. COMPETITOR CONTEXT - {{$json["competitor_comparison"] ? "Identify 2-3 likely competitors for this offering and what customers typically compare when choosing between them" : "Skip this section, return empty array"}}

4. INDUSTRY SPECIFIC CONCERNS - What are the top concerns unique to the {{$json["classification"]["industry"]}} industry that customers always ask about?

CRITICAL: Return ONLY valid JSON. No explanation. No markdown. No code fences.

OUTPUT FORMAT:
{
  "deep_dive": "string summarizing key details found",
  "customer_hesitations": ["string"],
  "competitor_context": ["string"],
  "industry_concerns": ["string"]
}

