parameters.text:
=You are an expert FAQ writer. You have deep context about a specific page and its customers. Generate highly targeted FAQs that feel like they were written exclusively for this offering.

--- CONTEXT ---
Brand: {{$json["classification"]["brand_name"]}}
Product/Service: {{$json["classification"]["product_name"] || "(brand-level)"}}
Industry: {{$json["classification"]["industry"]}}
Business Model: {{$json["classification"]["business_model"]}}
Buying Journey Stage: {{$json["classification"]["buying_journey_stage"]}}
Price Tier: {{$json["classification"]["price_tier"]}}
Target Customer: {{$json["classification"]["target_customer"]}}
Key USPs: {{$json["classification"]["top_usps"]}}

Deep Analysis: {{$json["deep_dive"]["deep_dive"]}}
Customer Hesitations: {{$json["deep_dive"]["customer_hesitations"]}}
Industry Concerns: {{$json["deep_dive"]["industry_concerns"]}}
{{$json["competitor_comparison"] ? "Competitor Context: " + $json["deep_dive"]["competitor_context"] : ""}}

Original Page Content:
{{$json["content"]}}

--- TASK ---
Generate exactly {{$json["faq_count"]}} FAQs.

STRICT RULES:
- Tone: {{$json["tone"]}}
- Language: {{$json["language"]}}
- Every FAQ must feel like it could ONLY belong to {{$json["classification"]["brand_name"]}} — not any generic brand
- Answers must reference specific details from the page content where possible
- Group by theme — themes must be specific to this industry, NOT generic (e.g. not just "Shipping" but "Delivery & Installation" for furniture, or "Onboarding & Setup" for SaaS)
- For {{$json["classification"]["buying_journey_stage"]}} stage: {{$json["is_decision_stage"] ? "Focus heavily on objection handling, trust signals, guarantees, and final purchase concerns" : $json["is_awareness_stage"] ? "Focus on education, what this is, who it is for, and how it works" : "Focus on comparison, features, value, and differentiators"}}
- Address all customer hesitations identified in the analysis
- Address all industry-specific concerns
{{$json["competitor_comparison"] ? "- Include 2-3 FAQs that directly address why this is better than or different from competitors" : ""}}
- NEVER write generic FAQ answers — every answer must contain something specific to this brand/product
- NEVER leave fields empty

CRITICAL: Return ONLY a valid JSON array. No explanation. No markdown. No code fences.

OUTPUT FORMAT:
[
  {
    "question": "string",
    "answer": "string",
    "theme": "string"
  }
]

parameters.jsCode:
let raw = $json.output || "";

raw = raw.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
raw = raw.replace(/\(no answer provided\)/g, 'Please contact support for more information.');
raw = raw.replace(/N\/A/g, 'Please contact support for more information.');

const start = raw.indexOf('[');
const end = raw.lastIndexOf(']');

let parsed = [];

try {
  if (start === -1 || end === -1) throw new Error("No JSON array found");
  parsed = JSON.parse(raw.slice(start, end + 1));

  parsed = parsed.filter(faq =>
    faq.question && faq.question.trim() !== '' &&
    faq.answer && faq.answer.trim() !== '' &&
    faq.theme && faq.theme.trim() !== ''
  );

  const seen = new Set();
  parsed = parsed.filter(faq => {
    const key = faq.question.toLowerCase().trim();
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });

} catch (e) {
  return [{ json: { error: "Invalid AI JSON output", raw: raw.slice(0, 500) } }];
}

const validateNode = $('Validate & Extract Inputs').first().json;
const classificationNode = $('Parse Classification').first().json;

return [{
  json: {
    faqs: parsed,
    faq_count_requested: validateNode.faq_count,
    faq_count_generated: parsed.length,
    classification: classificationNode.classification
  }
}];

const input = $json;

if (!input.faqs || input.faqs.length === 0 || input.error) {
  return [{
    json: {
      success: false,
      faqs: [],
      json_ld: {},
      shopify_html: "",
      chatbot_csv: "",
      objection_faqs: [],
      themes: [],
      classification: input.classification || {},
      error: input.error || "AI returned no valid FAQs"
    }
  }];
}

const faqs = input.faqs;
const classification = input.classification || {};
const safe = (val) => (val || "").replace(/"/g, '&quot;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const safeCsv = (val) => (val || "").replace(/"/g, '""');

const jsonLd = {
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": faqs.map(faq => ({
    "@type": "Question",
    "name": faq.question,
    "acceptedAnswer": {
      "@type": "Answer",
      "text": faq.answer
    }
  }))
};

const byTheme = {};
faqs.forEach(faq => {
  const theme = faq.theme || "General";
  if (!byTheme[theme]) byTheme[theme] = [];
  byTheme[theme].push(faq);
});

let html = '<div class="faq-container">\n';
Object.entries(byTheme).forEach(([theme, items]) => {
  html += `  <div class="faq-theme">\n    <h2 class="faq-theme-title">${safe(theme)}</h2>\n`;
  items.forEach(faq => {
    html += `    <div class="faq-item">\n      <h3 class="faq-question">${safe(faq.question)}</h3>\n      <p class="faq-answer">${safe(faq.answer)}</p>\n    </div>\n`;
  });
  html += '  </div>\n';
});
html += '</div>';

const csv = [
  "question,answer,theme",
  ...faqs.map(f => `"${safeCsv(f.question)}","${safeCsv(f.answer)}","${safeCsv(f.theme)}"`)
].join("\n");

const baseKeywords = ["price", "cost", "expensive", "return", "refund", "warranty", "guarantee", "delivery", "shipping", "competitor", "vs", "versus", "compare", "better", "difference", "cancel", "trial", "risk", "safe", "secure", "trust"];
const objections = faqs.filter(f =>
  baseKeywords.some(k =>
    (f.question || "").toLowerCase().includes(k) ||
    (f.theme || "").toLowerCase().includes(k)
  )
);

const themes = Object.keys(byTheme).map(theme => ({
  theme,
  count: byTheme[theme].length
}));

return [{
  json: {
    success: true,
    faq_count_requested: input.faq_count_requested,
    faq_count_generated: faqs.length,
    page_intelligence: {
      page_type: classification.page_type,
      industry: classification.industry,
      business_model: classification.business_model,
      brand_name: classification.brand_name,
      product_name: classification.product_name,
      price_tier: classification.price_tier,
      buying_journey_stage: classification.buying_journey_stage,
      target_customer: classification.target_customer
    },
    themes,
    faqs,
    json_ld: jsonLd,
    shopify_html: html,
    chatbot_csv: csv,
    objection_faqs: objections
  }
}];
